// Busca todos os leads salvos no Redis com prefixo cl_hist_
// e filtra os que precisam de follow up agora

// NOTA: Este nó usa o cliente Redis via HTTP interno do N8N
// Na prática, use o nó Redis nativo com operação KEYS + GET
// para buscar todos os históricos e filtrar os elegíveis

// Estrutura esperada de cada histórico no Redis:
// {
//   nome_lead, estagio_lead, numero_remetente, numero_receptor,
//   historico_mensagens, ultimo_contato, tentativas_followup,
//   proximo_followup, flags
// }

// Por enquanto retorna estrutura mock para desenvolvimento
// IMPLEMENTAR: buscar chaves cl_hist_* no Redis e filtrar

const agora = new Date();

// Simulação — em produção, buscar do Redis
const leadsMock = [
  {
    redis_chave: 'cl_hist_5566999990000_5566999990001',
    numero_remetente: '5566999990000',
    numero_receptor: '5566999990001',
    unidade_nome: 'Crystal Laser Sinop',
    cidade: 'Sinop',
    horario_semana: '08:00 às 19:00',
    horario_sabado: '08:00 às 16:00',
    horario_abertura_semana: 8,
    horario_fechamento_semana: 19,
    horario_abertura_sabado: 8,
    horario_fechamento_sabado: 16,
    nome_lead: 'Maria',
    estagio_lead: 'GHOST_24H',
    area_interesse: 'virilha completa',
    tentativas_followup: 0,
    ultimo_contato: new Date(agora - 24 * 60 * 60 * 1000).toISOString(),
    proximo_followup: agora.toISOString(),
    motivo_nao_fechou: '',
    historico_mensagens: []
  }
];

// Filtra apenas leads onde proximo_followup <= agora
const leadsElegiveis = leadsMock.filter(lead => {
  if (!lead.proximo_followup) return false;
  if (lead.tentativas_followup >= 3) return false;
  if (lead.estagio_lead === 'LEAD_ENCERRADO') return false;
  if (lead.estagio_lead === 'LEAD_FRIO_PAUSADO') return false;
  const proximo = new Date(lead.proximo_followup);
  return proximo <= agora;
});

if (leadsElegiveis.length === 0) {
  return [{ json: { sem_leads: true } }];
}

return leadsElegiveis.map(lead => ({ json: lead }));

const dados = $input.first().json;

const agora = new Date();
const horaBrasilia = new Date(agora.toLocaleString('en-US', { timeZone: 'America/Cuiaba' }));
const hora = horaBrasilia.getHours();
const diaSemana = horaBrasilia.getDay();

let dentroDoHorario = false;

if (diaSemana === 0) {
  dentroDoHorario = false;
} else if (diaSemana === 6) {
  dentroDoHorario = hora >= 9 && hora < 18;
} else {
  dentroDoHorario = hora >= 8 && hora < 20;
}

return [{
  json: {
    ...dados,
    dentro_do_horario: dentroDoHorario,
    hora_atual: hora,
    dia_semana: diaSemana
  }
}];

const dados = $input.first().json;
const fs = require('fs');

// Lê o system prompt do Follow Up
let systemPrompt = fs.readFileSync(
  '/home/iara/clients/Crystal-Laser/agents/followup_system_prompt.md',
  'utf8'
);

// Injeta variáveis de contexto
systemPrompt = systemPrompt
  .replaceAll('{{unidade_nome}}', dados.unidade_nome)
  .replaceAll('{{cidade}}', dados.cidade)
  .replaceAll('{{horario_semana}}', dados.horario_semana)
  .replaceAll('{{horario_sabado}}', dados.horario_sabado)
  .replaceAll('{{nome_lead}}', dados.nome_lead || '')
  .replaceAll('{{area_interesse}}', dados.area_interesse || 'não informada')
  .replaceAll('{{estagio_lead}}', dados.estagio_lead || 'GHOST_24H')
  .replaceAll('{{tentativas}}', String(dados.tentativas_followup || 0))
  .replaceAll('{{ultimo_contato}}', dados.ultimo_contato || '')
  .replaceAll('{{motivo_nao_fechou}}', dados.motivo_nao_fechou || 'não identificado');

// Monta histórico resumido para contexto
const historico = dados.historico_mensagens || [];
const historicoResumido = historico.slice(-6); // últimas 6 mensagens

// Instrução direta para o agente gerar a mensagem de follow up
const mensagemUsuario = `Gere a mensagem de follow up adequada para este lead.
Estágio atual: ${dados.estagio_lead}
Tentativa número: ${dados.tentativas_followup + 1} de 3
Último contato: ${dados.ultimo_contato}
Histórico resumido: ${JSON.stringify(historicoResumido)}

Gere apenas a mensagem a ser enviada, sem explicações adicionais.`;

return [{
  json: {
    ...dados,
    system_prompt_final: systemPrompt,
    messages_payload: [{ role: 'user', content: mensagemUsuario }]
  }
}];

const dados = $input.first().json;
const claudeResponse = dados.content?.[0]?.text || '';

// Detecta tags de controle
const retornarSdr = claudeResponse.includes('[RETORNAR_SDR]');
const escalarHumano = claudeResponse.includes('[ESCALAR_HUMANO]');
const escalarMenor = claudeResponse.includes('[ESCALAR_MENOR]');
const encerrarVitiligo = claudeResponse.includes('[ENCERRAR_VITILIGO]');
const leadEncerrado = claudeResponse.includes('[LEAD_ENCERRADO]');
const leadFrioPausado = claudeResponse.includes('[LEAD_FRIO_PAUSADO]');

// Limpa a resposta
const respostaLimpa = claudeResponse
  .replace(/\[RETORNAR_SDR\]/g, '')
  .replace(/\[ESCALAR_HUMANO\]/g, '')
  .replace(/\[ESCALAR_MENOR\]/g, '')
  .replace(/\[ENCERRAR_VITILIGO\]/g, '')
  .replace(/\[LEAD_ENCERRADO\]/g, '')
  .replace(/\[LEAD_FRIO_PAUSADO\]/g, '')
  .trim();

// Determina ação
let acao_principal = 'ENVIAR_FOLLOWUP';
if (escalarHumano) acao_principal = 'ESCALAR_HUMANO';
else if (escalarMenor) acao_principal = 'ESCALAR_MENOR';
else if (encerrarVitiligo) acao_principal = 'ENCERRAR_VITILIGO';
else if (retornarSdr) acao_principal = 'RETORNAR_SDR';
else if (leadEncerrado) acao_principal = 'LEAD_ENCERRADO';
else if (leadFrioPausado) acao_principal = 'LEAD_FRIO_PAUSADO';

// Calcula próximo follow up conforme tentativa
const tentativaAtual = dados.tentativas_followup || 0;
const intervalos = [0, 2, 2, 2]; // dias até próximo contato
const diasAteProximo = intervalos[tentativaAtual + 1] || 0;
const proximoFollowUp = new Date();
proximoFollowUp.setDate(proximoFollowUp.getDate() + diasAteProximo);

return [{
  json: {
    ...dados,
    resposta_final: respostaLimpa,
    acao_principal,
    tentativas_followup: tentativaAtual + 1,
    proximo_followup: diasAteProximo > 0 ? proximoFollowUp.toISOString() : null,
    historico_mensagens_atualizado: [
      ...(dados.historico_mensagens || []),
      { role: 'assistant', content: respostaLimpa, timestamp: new Date().toISOString(), tipo: 'FOLLOW_UP' }
    ]
  }
}];

