const dados = $input.first().json;

const historicoParaSalvar = {
  nome_lead: dados.nome_lead || '',
  estagio_lead: dados.acao_principal === 'LEAD_ENCERRADO' ? 'LEAD_ENCERRADO' 
    : dados.acao_principal === 'LEAD_FRIO_PAUSADO' ? 'LEAD_FRIO_PAUSADO'
    : dados.estagio_lead,
  area_interesse: dados.area_interesse || '',
  combo_apresentado: dados.combo_apresentado || '',
  forma_pagamento_escolhida: dados.forma_pagamento_escolhida || '',
  tentativas_followup: dados.tentativas_followup || 0,
  ultimo_contato: new Date().toISOString(),
  proximo_followup: dados.proximo_followup || null,
  motivo_nao_fechou: dados.motivo_nao_fechou || '',
  flags: dados.flags || [],
  historico_mensagens: dados.historico_mensagens_atualizado || [],
  atualizado_em: new Date().toISOString(),
};

return [{
  json: {
    redis_chave: dados.redis_chave,
    redis_valor: JSON.stringify(historicoParaSalvar),
    redis_ttl: 2592000,
  }
}];
